function CatalogSuggestionCenter({ locale, authToken }: { locale: Locale; authToken: string }) {
  const [form, setForm] = useState({
    type: "new_item" as "new_item" | "modify",
    nameZh: "",
    nameEn: "",
    category: "developer",
    remark: "",
    playbookYaml: "",
    guideMarkdown: ""
  });
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState("");

  async function submit() {
    setMessage("");
    if (!authToken) {
      setMessage("Please sign in before submitting a suggestion.");
      return;
    }
    if (!form.nameZh.trim() && !form.nameEn.trim()) {
      setMessage("Please enter at least one name.");
      return;
    }
    setSaving(true);
    try {
      await submitSuggestion(authToken, {
        type: form.type,
        nameZh: form.nameZh.trim() || form.nameEn.trim(),
        nameEn: form.nameEn.trim() || form.nameZh.trim(),
        category: form.category,
        remark: form.remark,
        playbookYaml: form.playbookYaml,
        guideMarkdown: form.guideMarkdown
      });
      setMessage("Suggestion submitted for review.");
      setForm((prev) => ({ ...prev, nameZh: "", nameEn: "", remark: "", playbookYaml: "", guideMarkdown: "" }));
    } catch (err) {
      setMessage(err instanceof Error ? err.message : "Submit failed");
    } finally {
      setSaving(false);
    }
  }

  return (
    <section className="suggestion-center">
      <div className="suggestion-copy">
        <p className="eyebrow">Community suggestions</p>
        <h2>Suggest software or a configuration combo</h2>
        <p>Use this for market-wide ideas. Open an item MD guide for item-specific comments and changes.</p>
      </div>
      <div className="suggestion-form">
        <div className="segmented-field">
          <button type="button" className={form.type === "new_item" ? "active" : ""} onClick={() => setForm((prev) => ({ ...prev, type: "new_item" }))}>New item</button>
          <button type="button" className={form.type === "modify" ? "active" : ""} onClick={() => setForm((prev) => ({ ...prev, type: "modify" }))}>Improve combo</button>
        </div>
        <div className="form-grid">
          <input value={form.nameZh} onChange={(e) => setForm((prev) => ({ ...prev, nameZh: e.target.value }))} placeholder="Chinese name" />
          <input value={form.nameEn} onChange={(e) => setForm((prev) => ({ ...prev, nameEn: e.target.value }))} placeholder="English name" />
          <select value={form.category} onChange={(e) => setForm((prev) => ({ ...prev, category: e.target.value }))}>
            {["runtime", "developer", "database", "container", "security", "network", "service"].map((category) => <option key={category} value={category}>{category}</option>)}
          </select>
        </div>
        <textarea value={form.remark} onChange={(e) => setForm((prev) => ({ ...prev, remark: e.target.value }))} rows={4} placeholder="Describe use cases and why it belongs in the catalog" />
        <textarea value={form.playbookYaml} onChange={(e) => setForm((prev) => ({ ...prev, playbookYaml: e.target.value }))} rows={7} placeholder="playbook.yaml (optional)" />
        <textarea value={form.guideMarkdown} onChange={(e) => setForm((prev) => ({ ...prev, guideMarkdown: e.target.value }))} rows={7} placeholder="guide.md (optional)" />
        <button className="primary-action" type="button" disabled={saving} onClick={() => void submit()}>{saving ? "Submitting..." : "Submit suggestion"}</button>
        {message ? <p className="settings-help">{message}</p> : null}
      </div>
    </section>
  );
}
